const express = require('express');
const crypto = require('crypto');
const app = express();
const clients = new Map();
const authCodes = new Map();
const accessTokens = new Map();

// Client registration
clients.set('client1', {
  client_id: 'client1',
  client_secret: crypto.createHash('sha256').update('secret1').digest('hex'),
  redirect_uris: ['http://localhost:3000/callback'],
  allowed_grants: ['authorization_code']
});

clients.set('client2', {
  client_id: 'client2',
  client_secret: crypto.createHash('sha256').update('secret2').digest('hex'),
  redirect_uris: ['http://localhost:3001/callback'],
  allowed_grants: ['authorization_code']
});

// Middleware
app.use(express.urlencoded({ extended: true }));
app.use(express.json());

// Login page
app.get('/login', (req, res) => {
  res.send(`
    <form method="post" action="/authorize">
      <input type="hidden" name="client_id" value="${req.query.client_id}">
      <input type="hidden" name="redirect_uri" value="${req.query.redirect_uri}">
      <input type="hidden" name="state" value="${req.query.state}">
      <input type="hidden" name="response_type" value="code">
      <p>Username: <input type="text" name="username" required></p>
      <p>Password: <input type="password" name="password" required></p>
      <button type="submit">Login</button>
    </form>
  `);
});

// Authorization endpoint
app.get('/authorize', (req, res) => {
  const { client_id, redirect_uri, state, response_type } = req.query;
  
  if (!client_id || !redirect_uri || !response_type) {
    return res.status(400).json({ error: 'invalid_request' });
  }
  
  const client = clients.get(client_id);
  if (!client) {
    return res.status(400).json({ error: 'invalid_client' });
  }
  
  if (!client.redirect_uris.includes(redirect_uri)) {
    return res.status(400).json({ error: 'invalid_request' });
  }
  
  if (response_type !== 'code') {
    return res.status(400).json({ error: 'unsupported_response_type' });
  }
  
  res.redirect(`/login?client_id=${client_id}&redirect_uri=${encodeURIComponent(redirect_uri)}&state=${state}`);
});

// Handle login and generate authorization code
app.post('/authorize', (req, res) => {
  const { client_id, redirect_uri, state, username, password } = req.body;
  
  const client = clients.get(client_id);
  if (!client) {
    return res.status(400).json({ error: 'invalid_client' });
  }
  
  if (!client.redirect_uris.includes(redirect_uri)) {
    return res.status(400).json({ error: 'invalid_request' });
  }
  
  // Simple authentication (in production, use proper auth)
  if (username !== 'user' || password !== 'password') {
    return res.status(401).json({ error: 'invalid_grant' });
  }
  
  const authCode = crypto.randomBytes(32).toString('hex');
  const codeExpiry = Date.now() + 300000; // 5 minutes
  
  authCodes.set(authCode, {
    client_id,
    redirect_uri,
    state,
    expires_at: codeExpiry,
    user_id: username
  });
  
  const redirectUrl = `${redirect_uri}?code=${authCode}&state=${state}`;
  res.redirect(redirectUrl);
});

// Token endpoint
app.post('/token', (req, res) => {
  const { grant_type, client_id, client_secret, code, redirect_uri } = req.body;
  
  if (grant_type !== 'authorization_code') {
    return res.status(400).json({ error: 'unsupported_grant_type' });
  }
  
  const client = clients.get(client_id);
  if (!client) {
    return res.status(400).json({ error: 'invalid_client' });
  }
  
  if (client_secret !== client.client_secret) {
    return res.status(400).json({ error: 'invalid_client' });
  }
  
  if (!code) {
    return res.status(400).json({ error: 'invalid_request' });
  }
  
  const authCode = authCodes.get(code);
  if (!authCode) {
    return res.status(400).json({ error: 'invalid_grant' });
  }
  
  if (authCode.expires_at < Date.now()) {
    authCodes.delete(code);
    return res.status(400).json({ error: 'invalid_grant' });
  }
  
  if (authCode.redirect_uri !== redirect_uri) {
    return res.status(400).json({ error: 'invalid_grant' });
  }
  
  // Generate access token
  const accessToken = crypto.randomBytes(32).toString('hex');
  const tokenExpiry = Date.now() + 3600000; // 1 hour
  
  accessTokens.set(accessToken, {
    client_id,
    user_id: authCode.user_id,
    expires_at: tokenExpiry
  });
  
  // Remove used authorization code
  authCodes.delete(code);
  
  res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: 3600
  });
});

// Token introspection endpoint
app.post('/introspect', (req, res) => {
  const { token } = req.body;
  
  const tokenData = accessTokens.get(token);
  if (!tokenData) {
    return res.json({ active: false });
  }
  
  if (tokenData.expires_at < Date.now()) {
    accessTokens.delete(token);
    return res.json({ active: false });
  }
  
  res.json({
    active: true,
    client_id: tokenData.client_id,
    user_id: tokenData.user_id,
    expires_at: tokenData.expires_at
  });
});

